const rawData = $input.all()[0].json.data;

// 1. EXTRACTION DU NOM DU CLIENT
const clientRow = rawData.find(row => row["DT"] === "Nom client ");
const clientName = clientRow ? (clientRow["DTM50056"] || "").trim().replace(/\s+/g, '_') : "Client";
const finalFileName = `3cx_import_${clientName}.csv`;

// 2. FILTRER LES UTILISATEURS VALIDES
const users = rawData.filter(row => {
    const extValue = row["__EMPTY_1"];
    return extValue && !isNaN(extValue) && extValue !== "Extension";
});

// 3. ANNUAIRE POUR LES BLF
const directory = users.map(u => ({
    number: u["__EMPTY_1"].toString(),
    name: `${u["DT"] || ""} ${u["DTM50056"] || ""}`.trim()
}));

// 4. SET POUR LE CONTROLE DES DOUBLONS D'EMAIL ET DID
const seenEmails = new Set();
const seenDIDs = new Set();

// 5. TRANSFORMATION
return users.map(row => {
    const currentExt = row["__EMPTY_1"].toString();
    const excelModel = (row["__EMPTY_4"] || "").toUpperCase().trim();

    // --- GESTION DES DOUBLONS D'EMAIL ---
    let email = (row["__EMPTY_7"] || "").replace(/\s/g, '').replace(/@$/, '');
    if (seenEmails.has(email.toLowerCase())) {
        email = "";
    } else if (email !== "") {
        seenEmails.add(email.toLowerCase());
    }

    // --- LOGIQUE WEBMEETING FRIENDLY NAME ---
    const baseName = (row["DT"] || row["DTM50056"] || "User").replace(/[^a-zA-Z0-9]/g, '');
    const extSuffix = currentExt.slice(-3); 
    const friendlyName = baseName.substring(0, 7).toLowerCase() + extSuffix;

    // --- LOGIQUE DID (SDA / Appels entrants) ---
    let didValue = (row["__EMPTY_2"] || "").toString().trim();
    if (didValue.length === 9 && didValue.startsWith("596")) {
        // 596123456 -> 596596123456
        didValue = "596" + didValue;
    } else if (didValue.length === 10 && didValue.startsWith("0596")) {
        // 0596123456 -> 596596123456
        didValue = "596" + didValue.substring(1);
    }
    // Gestion des doublons de DID
    if (didValue !== "" && seenDIDs.has(didValue)) {
        didValue = "";
    } else if (didValue !== "") {
        seenDIDs.add(didValue);
    }

    // --- LOGIQUE OutboundCallerID (Affichage appels sortants) ---
    let outboundCallerID = (row["__EMPTY_3"] || "").toString().trim();
    if (outboundCallerID.length === 9 && outboundCallerID.startsWith("596")) {
        // 596123456 -> 0596123456
        outboundCallerID = "0" + outboundCallerID;
    }

    // --- LOGIQUE MODÈLES, MAC ET ROUTEUR ---
    let model3CX = "";
    let template3CX = "";
    let macAddress = "";
    let routerValue = "";

    const dectModels = ["W56H", "W74H", "W59R"];
    const isDect = dectModels.some(m => excelModel.includes(m));

    if (!isDect) {
        template3CX = "yealinkT4x.ph.xml";
        macAddress = (row["À compléter : par Dauphin Télécom"] || "").replace(/[:.-]/g, '');
        routerValue = (row["__EMPTY_9"] || "").trim();

        if (excelModel.includes("T34")) {
            model3CX = "Yealink T34W";
        } else if (excelModel.includes("T57")) {
            model3CX = "Yealink T57W";
        } else {
            model3CX = "Yealink T54W";
        }
    }

    // --- XML CONFIGURATIONS ---
    const otherUsers = directory.filter(u => u.number !== currentExt);
    let blfXml = '<PhoneDevice><BLFS>';
    otherUsers.slice(0, 15).forEach((user, index) => {
        blfXml += `<BLF BLFNo="${index + 1}" BLFType="BLF" BLFTypeID="0" ID="${user.number}">${user.name}</BLF>`;
    });
    blfXml += '</BLFS></PhoneDevice>';

    const phoneSettingsXml = `<PhoneDevice ProvType="0" Secret="" PhoneLanguage="French" XferType="BXfer" RingTone="Ring 1" QueueRingTone="Ring 6" DateFormat="DD MMM YYYY (15 Jan 2017)" TimeFormat="24-hour clock" PowerLed="Both (Voicemail and Missed calls)" Backlight="15 seconds" ScreenSaver="15 seconds"><CustomQueueRingTones /><mcgroups enabled="false" /><DynamicOptions><option name="vlanwanport" value="False" /><option name="vlanwanid" value="1" /><option name="vlanwanpriority" value="0" /><option name="vlanpcport" value="False" /><option name="vlanpcid" value="1" /><option name="vlanpcpriority" value="0" /></DynamicOptions><LldpOptions><option name="lldpvalue" value="True" /></LldpOptions><CodecsPriority><Codec Priority="1" PriorityVarName="codec1" DisplayText="G722" PayloadTypeName="payload3" payload="G722">9</Codec><Codec Priority="2" PriorityVarName="codec2" DisplayText="PCMA" PayloadTypeName="payload2" payload="PCMA">8</Codec><Codec Priority="3" PriorityVarName="codec3" DisplayText="PCMU" PayloadTypeName="payload1" payload="PCMU">0</Codec><Codec Priority="4" PriorityVarName="codec4" DisplayText="G729" PayloadTypeName="payload4" payload="G729">18</Codec></CodecsPriority></PhoneDevice>`;

    return {
        json: {
            "TEMP_FILENAME": finalFileName,
            "Number": currentExt,
            "FirstName": row["DTM50056"] || "",
            "LastName": row["DT"] || "",
            "EmailAddress": email,
            "MobileNumber": "",
            "OutboundCallerID": outboundCallerID,
            "DID": didValue,
            "Role": '<role name="users" />',
            "Department": row["__EMPTY"] || "DEFAULT",
            "ClickToCallAuth": "0",
            "WMApprove": "0",
            "WebMeetingFriendlyName": friendlyName,
            "MAC": macAddress,
            "Template": template3CX,
            "Model": model3CX,
            "Router": routerValue,
            "Language": "French",
            "Ringtone": "Ring 1",
            "QRingtone": "Ring 6",
            "VMEnable": "1",
            "VMLanguage": "0D767FEA-10A3-4ba4-8A57-FE74BDABE4E5",
            "VMPlayMsgDateTime": "0",
            "VMPIN": "",
            "VMEmailOptions": "0",
            "VMNoPin": "1",
            "VMPlayCallerID": "0",
            "RecordCalls": "0",
            "RecordExternal": "0",
            "RecordCanSee": "0",
            "RecordCanDelete": "0",
            "RecordStartStop": "0",
            "RecordNotify": "0",
            "Disabled": "0",
            "HideFWrules": "0",
            "DisableExternalCalls": "0",
            "HideInPhonebook": "0",
            "CallScreening": "0",
            "PinProtected": "0",
            "PinTimeout": "0",
            "Transcription": "0",
            "AllowLanOnly": "1",
            "SIPID": "",
            "DeliverAudio": "1",
            "HotDesk": "0",
            "SRTPMode": "0",
            "EmailMissedCalls": "0",
            "MS365SignInDisabled": "",
            "MS365CalendarDisabled": "",
            "MS365ContactsDisabled": "",
            "MS365TeamsDisabled": "",
            "GoogleSignInDisabled": "",
            "GoogleContactsDisabled": "",
            "GoogleCalendarDisabled": "",
            "PhoneSettings": phoneSettingsXml,
            "BLF": blfXml
        }
    };
});

const rawData = $input.all()[0].json.data;

// 1. EXTRACTION DES METADONNEES (Nom client et Site Code)
const clientRow = rawData.find(row => row["DT"] === "Nom client ");
const clientName = clientRow ? (clientRow["DTM50056"] || "").trim().replace(/\s+/g, '_') : "Client";
// Génération du siteCode au format mtq-3cx-[nom-client]-1
const siteCode = `mtq-3cx-${clientName.toLowerCase()}-1`;
const finalFileName = `ymcs_import_${clientName}.xlsx`;

// 2. FILTRER LES UTILISATEURS VALIDES (Extension >= 2000)
const validRows = rawData.filter(row => {
    const ext = parseInt(row["__EMPTY_1"]);
    return !isNaN(ext) && ext >= 2000;
});

// 3. TRAITEMENT DES DONNEES ET REGROUPEMENT MAC (Spécial W56H)
const deviceMap = new Map();

validRows.forEach(row => {
    // Nettoyage MAC : suppression tirets, espaces, mise en majuscules
    let mac = (row["À compléter : par Dauphin Télécom"] || "").replace(/[:.-]/g, '').trim().toUpperCase();
    const sn = (row["__EMPTY_8"] || "").trim(); // S/N column
    const extension = row["__EMPTY_1"].toString();
    const nom = (row["DT"] || "").trim();
    const prenom = (row["DTM50056"] || "").trim();
    let excelModel = (row["__EMPTY_4"] || "").trim();

    if (!mac) return; // On ignore les lignes sans MAC

    // RÈGLE DE SUBSTITUTION / STANDARDISATION MODÈLE
    let finalModel = excelModel;
    if (excelModel === "SIP-W70+W56H") {
        finalModel = "W70B";
    } else if (excelModel === "SIP-T54" || excelModel === "T54") {
        finalModel = "SIP-T54W";
    } else if (excelModel === "SIP-T34" || excelModel === "T34") {
        finalModel = "SIP-T34W";
    } else if (excelModel === "SIP-T57" || excelModel === "T57") {
        finalModel = "SIP-T57W";
    } else if (/^T\d+/.test(excelModel)) {
        // Si commence par T sans SIP- (ex: T31P)
        finalModel = `SIP-${excelModel}`;
    }

    // GESTION DU DEVICE NAME
    let currentDisplayName = prenom ? `${nom} ${prenom}` : nom;

    // RÈGLE SPÉCIALE W56H (Regroupement par MAC)
    if (finalModel.includes("W56H") || finalModel.includes("W74H") || finalModel.includes("W59R")) {
        if (deviceMap.has(mac)) {
            // Si la MAC existe déjà, on ajoute l'extension au nom existant
            const existing = deviceMap.get(mac);
            existing.extensions.push(extension);
            existing.DeviceName = `BASE - ${existing.extensions.join(' ')}`;
        } else {
            // Première occurrence du sans-fil
            deviceMap.set(mac, {
                MAC: mac,
                MachineID: sn,
                Model: finalModel,
                DeviceName: `BASE - ${extension}`,
                extensions: [extension], // Pour le suivi interne
                Site: siteCode
            });
        }
    } else {
        // POSTE FIXE NORMAL (T5x, T3x, etc.)
        const deviceName = `${extension} - ${currentDisplayName}`;
        deviceMap.set(mac, {
            MAC: mac,
            MachineID: sn,
            Model: finalModel,
            DeviceName: deviceName,
            Site: siteCode
        });
    }
});

// 4. FORMATAGE FINAL POUR YMCS
const devices = Array.from(deviceMap.values()).map(device => ({
    "MAC": device.MAC,
    "Machine ID(Serial Number)": device.MachineID,
    "Model": device.Model,
    "Device Name": device.DeviceName,
    "Site": device.Site,
    "Unique URL": "",
    "User Name": "",
    "Password": "",
    "Description": "",
    "Account Type": "",
    "Account Info": "",
    "Account Line": "",
    // Métadonnée pour le nœud Spreadsheet File (ne sera pas dans le fichier si on filtre)
    "TEMP_FILENAME": finalFileName 
}));

return devices.map(d => ({ json: d }));
